{"Question": "How can I apply custom aggregation functions to moving windows?", "Context": "I want to calculate custom statistics like skewness or kurtosis over moving windows to understand data distribution changes.", "Code_Example": "import numpy as np
from movingaverages import MovingAggrPipe, moving_aggregate

# Define custom functions
def custom_skewness(x):
    if len(x) < 3:
        return np.nan
    n = len(x)
    mean = np.mean(x)
    std = np.std(x, ddof=1)
    if std == 0:
        return 0
    return (np.sum((x - mean) ** 3) / n) / (std ** 3)

def custom_kurtosis(x):
    if len(x) < 4:
        return np.nan
    n = len(x)
    mean = np.mean(x)
    std = np.std(x, ddof=1)
    if std == 0:
        return 0
    return (np.sum((x - mean) ** 4) / n) / (std ** 4) - 3

# Apply custom aggregations
custom_analysis = pipeline | moving_aggregate(
    columns='close_price',
    function=custom_skewness,
    window=30,
    output_suffix='_skew'
) | moving_aggregate(
    columns='close_price',
    function=custom_kurtosis,
    window=30,
    output_suffix='_kurt'
)

print("Custom Distribution Metrics:")
print(f"Current skewness: {custom_analysis.data['close_price_skew'].iloc[-1]:.3f}")
print(f"Current kurtosis: {custom_analysis.data['close_price_kurt'].iloc[-1]:.3f}")

# Interpret the results
skew = custom_analysis.data['close_price_skew'].iloc[-1]
if abs(skew) > 0.5:
    direction = "right-skewed" if skew > 0 else "left-skewed"
    print(f"Distribution is {direction}")", "Usage": "moving_aggregate(columns='close_price', function=custom_skewness, window=30, output_suffix='_skew')"}
